INSERT INTO `Boards` VALUES (1,1,'cornel',0,1,0,12,31,'Cave Location','=========================\rSquirrel Cave (049, 046) \r\rRat Cave (030 , 057)\r\rBat Cave (040 , 057)\r\rSnake Cave (030, 065)\r\rBear Cave (040, 065)\r\rWarthog Cave (030, 073)\r\rFox Cave (040, 073)\r\rScorpion Cave (063, 032)\r\rSkeleton Rogue Poet Cave (099, 046)\r\rSkeleton Warrior Mage Cave (108, 046)\r\rOgre Cave (074, 032)\r\rUnderwater Cave (075, 071)\r\rNinja Cave (084, 071)\r==========================',1),(2,1,'cornel',0,1,0,12,31,'Mystery box','You can buy 4 kind of mystery box\r\r1. Helm Mystery Box contain:\r   60% Novice Helm\r   30% Enchanted Helm\r   10% Royal Helm\r\r2. Accesory Mystery Box contain:\r   60% Faded Ring\r   30% Lustrous Ring\r   10% Celestial Ring\r\r3. Hand Item Mystery Box contain:\r   60% Faded Diamond\r   30% Lustrous Diamond\r   10% Celestial Diamond\r\r4. Shield Mystery Box contain:\r   60% Novice Shield\r   30% Enchanted Shield\r   10% Royal Shield\r\r\rItems Info\r=========================================================\r|  Name              |   AC   |    Vita    |    Mana    |\r=========================================================\r| Novice Helm        |   -2   |     500    |     250    |\r| Enchanted Helm     |   -6   |    3000    |    1500    | \r| Royal Helm         |  -10   |   15000    |    7500    |\r=========================================================\r| Faded Ring         |   -1   |     100    |      50    |\r| Lustrous Ring      |   -4   |     500    |     250    | \r| Celestial Ring     |  -15   |    3000    |    1500    |\r=========================================================\r| Faded Diamond      |   -1   |     100    |      50    |\r| Lustrous Diamond   |   -4   |     500    |     250    | \r| Celestial Diamond  |  -15   |    3000    |    1500    |\r=========================================================\r| Novice Shield      |   -3   |     500    |       0    |\r| Enchanted Shield   |  -11   |    3000    |     500    | \r| Royal Shield       |  -25   |   15000    |    5000    |\r=========================================================\r| Novice Buckler     |   -4   |     300    |     100    |\r| Enchanted Buckler  |  -12   |    2000    |    1000    | \r| Royal Buckler      |  -26   |   10000    |    7500    |\r=========================================================\r| Novice Wards       |   -1   |     100    |     200    |\r| Enchanted Wards    |   -9   |    1000    |    1500    | \r| Royal Wards        |  -23   |    5000    |   10000    |\r=========================================================\r| Novice Charm       |   -2   |     200    |     150    |\r| Enchanted Charm    |  -10   |    1500    |    1250    | \r| Royal Charm        |  -24   |    8000    |    8500    |\r=========================================================\r',2),(3,1,'cornel',0,1,0,12,31,'Enhcant Helm Shield, ACC, Hand','Go To NPC 50 81\rHelm, Shield, Acc, Hand Items\r \rYou can enchant your weapon using\r100 topaz\r100 quartz\r100 amethyts\r20.000 gold\r\r+1 90% chance of success\r+2 80% chance of success\r+3 70% chance of success\r+4 60% chance of success\r+5 50% chance of success \r+6 40% chance of success \r+7 30% chance of success\r\r+1 min lv 30\r+2 min lv 35\r+3 min lv 40\r+4 min lv 45\r+5 min lv 55\r+6 min lv 70\r+7 min lv 85 ',3),(4,1,'cornel',0,1,0,12,31,'Learn Essence','When you are lv 30 go to your tutor and say \"essence\"\r\rGo to essence npc and say your tutor name\r\rHe will ask you to collect some items\r\rGo back to essence npc after you bring the items and say\r\"essence\"\r\rAfter finish you can click the essence npc and start making the\rweapon and armor essence\r\rWhen you have the essence go to your tutor and say\r\"weapon essence\" for weapon\r\"armor essence\" for armor \r\rAs reward you will get new weapon and new armor',4),(6,1,'cornel',0,1,0,1,1,'Crown and Mantle Creation','Visit NPC 49 69.\r\rThe creation success rate is 100%,\rbut you will receive a random type.\r\rThere are four unique types of crowns and mantles:\rWater, Fire, Wind, and Wood.\r\rChoose the one that suits your gaming style.\r\rHappy gaming!\r',6),(7,1,'cornel',0,1,0,1,1,'Creation Item','Go to 55 53\r\rThere is NPC to make creation item\r\rdo not need to use SHIFT + I anymore',7),(8,1,'cornel',0,1,0,1,1,'Crown, necklace, mantle, boots Status','Water Type\r      Vita     Mana    Attack\r+ 0   2000     1500      5\r+ 1   2250     1750     10\r+ 2   2500     2000     15\r+ 3   2750     2250     25\r+ 4   3000     2500     30\r+ 5   3250     2750     35\r+ 6   3500     3000     40\r+ 7  10000    10000     70\r\rFire Type\r      Vita     Mana    Attack\r+ 0   1000     2000      5\r+ 1   1250     2250     10\r+ 2   1500     2500     15\r+ 3   1750     2750     25\r+ 4   2000     3000     30\r+ 5   2250     3250     35\r+ 6   2500     3500     40\r+ 7   5000    12500     45\r\rWind Type\r      Vita     Mana    Attack\r+ 0   3000     1000      5\r+ 1   3250     1250     10\r+ 2   3500     1500     15\r+ 3   3750     1750     25\r+ 4   4000     2000     30\r+ 5   4250     2250     35\r+ 6   4500     2500     40\r+ 7  15000     7500    150\r\rWood Type\r      Vita     Mana    Attack\r+ 0   5000        0      5\r+ 1   5250      250     10\r+ 2   5500      500     15\r+ 3   5750      750     25\r+ 4   6000     1000     30\r+ 5   6250     1250     35\r+ 6   6500     1500     40\r+ 7  20000     5000    120',8),(9,1,'cornel',0,1,0,1,2,'DungeonWarperNPC','New npc at 052 057\r\rThis npc will teleport you to dungeon cave\r\rthis cave use to collect material items for creation\r\robisidan, limestone, fox fur and red fox fur',9),(10,1,'cornel',0,1,0,1,3,'Enchant Crown necklace mantle boots','Go To NPC 50 81\rCrown, necklace, mantle, boots\r \rYou can enchant your weapon using\r100 topaz\r100 quartz\r100 amethyts\r20.000 gold\r\r+1 90% chance of success\r+2 80% chance of success\r+3 70% chance of success\r+4 60% chance of success\r+5 50% chance of success \r+6 40% chance of success \r+7 30% chance of success\r\r+0 min lv 50\r+1 min lv 55\r+2 min lv 60\r+3 min lv 65\r+4 min lv 70\r+5 min lv 75\r+6 min lv 80 \r+7 min lv 85 ',10),(11,1,'cornel',0,1,0,1,3,'Forge Weapon and Armor','Go To NPC 50 71(Weapon forge) and 50 72(Armor forge)\r\r================================\r\rBlue Dragon Sword\r- 5 Broken blue dragon sword\r- 5 Blue Dragon scroll\r\rBlue Dragon Armor\r- 5 Broken blue dragon armor\r- 5 Dragon Armor scroll\r\r=================================\r\rWhite Tiger Blade\r- 5 Broken white tiger sword\r- 5 White tiger scroll\r\rWhite Tiger Armor\r- 5 Broken white tiger armor\r- 5 Tiger armor scroll\r\r==================================\r\rRed Phoenix Staff\r- 5 Broken red phoenix sword\r- 5 Red phoenix Scroll\r\rRed Phoenix Armor\r- 5 Broken red phoenix armor\r- 5 Phoenix armor scroll\r\r==================================\r\rBlack Turtle Fan\r- 5 Broken black turtle sword\r- 5 Black turtle Scroll\r\rBlack Turtle Armor\r- 5 Broken black turtle armor\r- 5 Turtle armor Scroll\r\r==================================',11),(13,1,'cornel',0,1,0,1,4,'Create Weapon Scroll','Go to Essence NPC to create the scroll it has 25% chance\rBlue Dragon Scroll \r- 1 Broken white tiger blade\r- 1 Broken Red Phoenix staff \r- 1 Broken Black Turtle fan \r- 50 warrior seal\r- 50 sword metal\r- 100 warrior bone\r- 50.000 gold\r\rWhite tiger scroll\r- 1 Broken blue dragon sword\r- 1 Broken Red Phoenix staff \r- 1 Broken Black Turtle fan \r- 50 rogue seal\r- 50 blade metal\r- 100 rogue bone\r- 50.000 gold\r\rRed phoenix scroll\r- 1 Broken blue dragon sword\r- 1 Broken white tiger blade\r- 1 Broken Black Turtle fan \r- 50 mage seal\r- 50 staff metal\r- 100 mage bone\r- 50.000 gold\r\rBlack turtle scroll\r- 1 Broken blue dragon sword\r- 1 Broken white tiger blade\r- 1 Broken Red Phoenix staff \r- 50 poet seal\r- 50 fan metal\r- 100 poet bone\r- 50.000 gold\r ',12),(14,1,'cornel',0,1,0,1,4,'Create Armor Scroll','Go to Essence NPC to create the scroll it has 25% chance\rDragon armor Scroll \r- 1 Broken white tiger armor\r- 1 Broken Red Phoenix armor \r- 1 Broken Black Turtle armor \r- 50 warrior seal\r- 50 dragon cloth\r- 100 warrior bone\r- 50.000 gold\r\rTiger armor scroll\r- 1 Broken blue dragon armor\r- 1 Broken Red Phoenix armor \r- 1 Broken Black Turtle armor \r- 50 rogue seal\r- 50 tiger cloth\r- 100 rogue bone\r- 50.000 gold\r\rPhoenix armor scroll\r- 1 Broken blue dragon armor\r- 1 Broken white tiger armor\r- 1 Broken Black Turtle armor \r- 50 mage seal\r- 50 jujak cloth\r- 100 mage bone\r- 50.000 gold\r\rTurtle armor scroll\r- 1 Broken blue dragon armor\r- 1 Broken white tiger armor\r- 1 Broken Red Phoenix armor \r- 50 poet seal\r- 50 turtle cloth\r- 100 poet bone\r- 50.000 gold',13),(15,1,'cornel',0,1,0,1,5,'GroveMart - Top Up Grove Coins','This NPC sell Item mall ( 050, 049 )\r\rIf you want to top up wa / wm / mail cornel',14),(17,1,'cornel',0,1,0,1,14,'What to to from Lv 5 - 99','=======\rLevel 5\r=======\r- choose your class\r- take killing quest from npc mayor\r- learn spell as soon as possible\r- do collecting item quest as many as you can\r  ( the reward increase when your level get higher )\r- do gold donation just for unleash first power requirement\r\r\r========\rLevel 25\r========\r- get your unleash first power at your tutor npc\r  ( you will get new weapon and armor )\r- buy mystery box helm, shield, accesory and hand items\r  ( try to get the royal and celestial )\r- do killing quest\r- do collecting items\r- do gold donation just for unleash second power requirement\r- farm items for creation quartz and fox tail\r  ( obsidian, limestone, fox fur, red fox fur)\r\r\r=============\rLevel 30 - 50\r=============\r- take the essence weapon and armor quest\r  ( it will increase your weapon and armor )\r- farm items\r  ( bones, ash, quartz, fox tail )\r- try to enchant your helm, shield, accesory and hand items\r  ( right now the min level for +7 eq is 30 )\r\r\r========\rLevel 50 \r========\r- chat GM you will get free materials to create\r  ( crown / necklace / mantle / boots )\r- try to enchant your helm, shield, accesory and hand items\r  ( right now the min level for +7 eq is 30 )\r\r\r========\rLevel 60\r========\r- get your unleash second power at your tutor npc\r  (it will increase some of your spell damage and reduce the aethers)\r- do killing quest\r  ( start from this level you go to dungeon cave from npc warper ( 52, 57 )\r- do collecting items\r- do gold donation just for unleash third power requirement\r- try to create crown / necklace / mantle / boots\r- farm items for creation quartz and fox tail\r  ( obsidian, limestone, fox fur, red fox fur)\r- try to enchant your helm, shield, accesory and hand items\r  ( right now the min level for +7 eq is 30 )\r\r\r========\rLevel 90\r========\r- get your unleash third power at your tutor npc\r(it will increase some of your spell damage and reduce the aethers)\r\r- do killing quest\r\r- do collecting items\r\r- do gold donation just for unleash third power requirement\r\r- farm items for forging weapon and armor\r( forging weapon and armor can be use at lv 95 )\r( check the requirement items from npc 50,69 and 51, 79)\r\r- farm items for creation\r\r- try to enchant your full equip\r( right now the min level for +7 eq is 30 )\r\r\r========\rLevel 95\r========\r- forge weapon and armor\r\r- farm items for creation or you can buy from mystery box npc\r\r- try to enchant your forge weapon and armor\r( your target is +7 full equip )\r\r\r========\rLevel 99\r========\r- at this state hopefully you already achieve +7 full equip\r\r- if your exp is full you (4294967295) you can sell exp for gold\r\r- you can start the rebirth quest click mayor to see the quest\r\r',15),(18,1,'cornel',0,1,0,1,14,'Quest Rebirth Blessings','When you achieve lv 99 and Finish Unleash Third Power\rYou can take this quest\r\r=========================================\rHelp Noel ( 107, 064 )\r=========================================\rSay \"help in creating an essence\"\rHe will ask you to bring\r10 animal essence\r10 warrior essence\r10 rogue essence\r10 mage essence\r10 poet essence\r\rYou can create those essence at\rluna craft npc ( 055, 053 )\r\r\r=========================================\rHelp Elara ( 029, 079 )\r=========================================\rSay \"help enchant a ring and a diamond\"\rShe will give you elara ring and elara diamond\r\rGo to Armor Smith\rEnchant elara ring to +7\rEnchant elara diamond to +7\r\rGo back to elara\rSay \"help enchant a ring and a diamond\"\r\r\r=========================================\rHelp Garron ( 068, 071)\r=========================================\rSay \"assisting in defeating a boss\"\rChoose yes\rHe will teleport you to boss arena\r\rAfter kill the boss\ryou will get Boss Trial Blood and\rautomaticaly teleport back to town\r\rSay \"blood\"\rto give the blood to garron\r\r**Notes\rYou can create party to kill the boss\r',16),(20,1,'cornel',0,1,0,1,14,'Create Subpath Essence','======================\rCreate Subpath Essence\r======================\rGo To Noel ( 107, 064 )\rAfter you complete quest help noel create essence\rNow You can click The NPC\r\rChoose the subpath do you want to choose\r\rBring all items he ask\r\rAs reward he will give you 2 essence :\r1 pcs of your choosen subpath weapon essence\r1 pcs of our choosen subpath armor essence\r',17),(21,1,'cornel',0,1,0,1,14,'Create Subpath Weapon and Armor Seal','==========================\rCreate Subpath Weapon Seal\r==========================\rGo To Elara ( 029, 079 )\rAfter you complete quest help elara enchant her diamond and ring\rNow You can click The NPC\r\rChoose the subpath do you want to choose\rBring the requirement item to elara and she will\rforge the subpath weapon seal for you\r\r=========================\rCreate Subpath Armor Seal\r=========================\rGo To Garron ( 068, 071 )\rAfter you complete quest help garron kill boss\rNow You can click The NPC\r\rChoose the subpath do you want to choose\rBring the requirement item to garron and he will\rforge the subpath armor seal for you\r',18),(22,1,'cornel',0,1,0,1,14,'Join Subpath','At your class hall, you will find two NPCs serving as your subpath gurus.\rTo join a subpath, you must present the following items:\r1 Subpath Weapon Seal\r1 Subpath Armor Seal\r\rFor Warriors, the choices are:\rBerserker\rGuardian\r\rFor Rogues, the choices are:\rAcrobat\rSaboteur\r\rFor Mages, the choices are:\rMystic\rElementalist\r\rFor Poets, the choices are:\rLyricist\rNaturalist\r\rUpon joining a subpath, you will undergo an automatic rebirth.\rThis transition sets your level back to 5\rBut fear not as your base vitality and base mana will significant increase.',19),(23,1,'cornel',0,1,0,1,14,'Broken Weapon and Armor Cave','=============================\rBroken Weapon Cave (075, 072)\r=============================\rRoom 1 drop broken black turtle fan\rRoom 2 drop broken red phoenix staff\rRoom 3 drop broken blue dragon sword\rRoom 4 drop broken white tiger blade\r\r\r============================\rBroken Armor Cave (075, 072)\r============================\rRoom 1 drop broken black turtle armor\rRoom 2 drop broken red phoenix armor\rRoom 3 drop broken blue dragon armor\rRoom 4 drop broken white tiger armor',20),(29,1,'Ruble',0,0,0,1,18,'Learn Essence (Lv 30)','When you are lv 30 go to your tutor and say \r<b>\"essence\"\r\rGo to essence npc and say\r<b>Your Tutor Name\r\rHe will ask you to collect some items\r\rGo back to essence npc after you bring the items and say\ryour\r<b>Your Tutor Name\r\rAfter finish you can click the essence npc and start making the\rweapon and armor essence\r\rWhen you have each of the essence go to your tutor and say\r<b> \"Weapon Essence\" for Weapon\r<b>\"Armor Essence\" for Armor \r\rAs reward you will get new weapon and new armor!',23),(30,1,'Devereux',0,0,0,1,18,'Essence NPC Location','Grove Town (038,035)',24),(31,1,'cornel',0,1,0,1,18,'Convert Exp to Vita / Mana','Go to 74, 40\r\rSay \"exp to vita\" or \"exp to mana\"\r\rit will need full bar of exp = 4.294.967.295\r\ryou vita / mana will add depends on your subpath',25),(37,1,'cornel',0,1,0,1,19,'Rage and Fury','Berseker rage\rR1 - Vita 350k =  80 * swingDamage  \rR2 - Vita 450k = 160 * swingDamage\rR3 - Vita 550k = 240 * swingDamage\r\rGuardian rage\rR1 - Vita 300k =  60 * swingDamage  \rR2 - Vita 400k = 120 * swingDamage\rR3 - Vita 500k = 180 * swingDamage\r\rSaboteur Fury\rC1 - Mana 180k = 100 * swingDamage\rC1 - Mana 230k = 200 * swingDamage\rC1 - Mana 280k = 300 * swingDamage\r\rCircus Mastery\rC1 - Mana 210k = 90 * swingDamage\rC1 - Mana 260k = 180 * swingDamage\rC1 - Mana 310k = 270 * swingDamage',26),(39,1,'Atlantis',0,0,0,1,25,'Animal Essence','Buat di : NPC 55,53\r\r<b>7 KIND OF MEAT\r--------------\r1. Rabbit Meat\r2. Rat Meat\r3. Snake Meat\r4. Fine Snake Meat\r5. Pork\r6. Fine Pork\r7. Tiger Meat\r\r<b>2 KIND OF HEART\r---------------\r1. Tiger Heart\r2. Bear Liver',28),(41,1,'cornel',0,1,0,1,27,'craft donation','Players can donate base items to a profession NPC.\rThe base items include base log, wool, liquid, and ore.\rDefault Rewards:\rBy default, for 1 seal, players get 400 - 800 base items.\rBy default, for 800 base items, players get 100 - 300 base items.\r\rAchievement Milestones:\rAt 500 donations:\rplayers receive a fixed amount of 800 base items.\r\rAt 1000 donations:\rthe range for base items becomes 800 - 1600\rplayers receive a fixed amount of 300 pure items\r\rAt 2000 donations:\rthe range for base items becomes 1600 - 2400\rthe range for pure items becomes 300 - 600\r\rAt 4000 donations:\rthe range for pure items is 600 - 1200',30),(42,1,'cornel',0,1,0,1,28,'frienship orb','Learn Seal Blood Spell:\r\rVisit NPC Cornelius to learn the Seal Blood Spell.\rStand near your partner character.\rCast the Seal Blood Spell and input your partner\'s name.\rUpon success, you will receive the Seal Blood Legend.\r\r\rCraft Friendship Orb:\r\rHead to the Artisan NPC located at coordinates (48, 69).\rInteract with the Artisan NPC to access crafting options.\rCraft the Friendship Orb using the required materials.\rOnce crafted, you now have a Friendship Orb.',31),(43,1,'Djengis',0,0,0,1,28,'Subpath Spell','Yg belum ada nama spell belum akurat nanti diupdate lagi\r\r====================WARRIOR====================\rBerserker\r\rStormy Slash - AoE (24 tiles diamond shape) instant damage\rBlood Thirsty - Vampiric (gain HP each swing)\rSavage Precision - Single target vita attack (consume 50% HP)\rBerserker Rage - Cast warrior rage, bless, flank, backstab... ...(swing AoE 12 tiles diamond shape)\rJump - Jump 3 tiles ahead (5s cooldown)\rZerk Rampage - Gain full HP (can be cast only when HP below 5%)\r\r\rGuardian\r\r5s DoT sampe mp abis\rrage based on mp\rsingle target\rregen hp/mp\rhb 10s cd 16 consume huge mp\rburst 4s\r\r====================POET====================\rLyricist\r\rMelodic Symphony - Regen HP/MP\rMelodic Breeze - AoE damage over time\rSong of Renewal - Single target ressurection (able to self res)\rMyst Shield - Single target ASV\rMyst Dissonant - AoE instant damage\rHarmonic Resonance - Screen/room SC\rHarmonic Step - Jump 3 tiles ahead (5s cooldown)\r\r\rNaturalist\r\rNatures Guard - Group ASV\rTranquil Aura - Regen HP/MP (better than Lyricist)\rSpring Renewal - Single target ressurection (able to self res)\rNatures Wrath - AoE (screen/room) instant damage\rRealm Scourge - Screen/room SC\rNatures Happines - Group ressurection \rNatures Power - HB (16s active duration and 20s cooldown)\rArcane Resonance - AoE (screen/room) instant damage\rBack to Nature - Single target dispel\r\r====================ROGUE====================\rSaboteur\r\rToxic Veil - AoE (12 tiles diamond shape) instant damage\rShrouded Fury - Rogue cunning\rBurst - Jump 3 tiles ahead (no cooldown)\rSilent Whisper - Invisible (double swing damage)\rNimble Mirage - Chain damage (if your target instant killed)\rRejuvenate - Regen HP and a bit of MP (consume all MP)\rAmbush\rNoxious Cloud - AoE (12 tiles diamond shape) instant damage... ...(consume 50% HP)\r\r\rAcrobat (damage lebih based on mana sama vita dikit)\r\raoe DoT 5s cd 5s\rinvis\rcunning\rregen hp mp based on mp\rburst no delay\raoe damage\raoe damage dari jauh (bomb)\rambush\r\r====================MAGE====================\rMystic\r\rsingle para\rheal hp mp\raoe DoT\raoe para\raoe damage based on mana\rburst\r\r\rElementalist\r\rInvoke\rMeditate - HP regen\rFrost Nova - AoE (24 tiles diamond shape) damage over time\rCorrosive Wind - Vex\rFire Nova - AoE (24 tiles diamond shape) instant damage\rWind Bind - Single target paralyze\rPrism Force - Single target HF\rInferno Carnage - Screen/Room HF',32),(44,1,'cornel',0,1,0,2,4,'99 Max Stat','99 Max stat\rBerseker\rmax Vita = 360000\rmax Mana =  90000\r\rGuardian\rmax Vita = 300000\rmax Mana = 120000\r\rSabouter\rmax Vita = 260000\rmax Mana = 140000\r\rAcrobat\rmax Vita = 200000\rmax Mana = 170000\r\rMystic\rmax Vita = 140000\rmax Mana = 200000\r\rElementalis\rmax Vita =  60000\rmax Mana = 240000\r\rLyricist\rmax Vita = 180000\rmax Mana = 180000\r\rNaturalist\rmax Vita = 180000\rmax Mana = 180000\r',33),(46,1,'cornel',0,1,0,2,6,'Profession Level','each time you make fine items you get 1 point\r\r1 point = beginner \r50 point = novice \r100 point = apprentice \r150 point = accomplished \r200 point = adept\r\rwhen you react adept you can Forge Adept subpath weapon\r\r300 point = talented \r400 point = Skilled \r500 point = Expert \r600 point = Master\r \rwhen you react master you can Forge Master subpath weapon\r\r800 point = GrandMaster   \r1000 point = Champion \r1200 point = legendary \r\rwhen you react legendary you can Forge Legendary subpath weapon\r',34),(47,1,'cornel',0,1,0,2,6,'Blessing','You can purchase blessing to increase monster exp\rat f1 menu',35),(48,1,'cornel',0,1,0,2,6,'Forge Adept Weapon','When you reach level Adept Matallurgist\rYou can forge adept weapon for every subpath\r\rGo To Forge NPC ( 20, 97 )\rClick Forge Adept Weapon and choose the weapon\r\rYou should ask to bring\r5 basic gem\r10 weapon favor\r10 basic sword/blade/staff/fan depends on which weapon you choose\r20 catalysis\r100 fine metal\r+7 Your subpath weapon\r250.000.000 gold',36);
